function enrichRound(ep, round) {
  const guide = (roundStoryGuides[ep.id] || roundStoryGuides.island)[round.number - 1] || {};
  const primary = { ...round.choices.help_group, id:'primary_group', kind:'help_group', category:'Group Priority' };
  const secondaryDef = guide.secondary || ['Protect the Backup Plan','Support a second urgent group need.','campSafety',1];
  const secondary = choice(secondaryDef[0], secondaryDef[1], { id:'secondary_group', kind:'help_group', category:'Second Priority', energyCost:1, groupStat:secondaryDef[2], groupGain:secondaryDef[3] || 1 });
  const personal = { ...round.choices.help_self, id:'personal', kind:'help_self', category:'Personal Survival' };
  const risk = { ...round.choices.take_risk, id:'risk', kind:'take_risk', category:'High Risk' };
  const deceptionDef = guide.deception || ['Mislead the Group','Create a private advantage while the group is distracted.','personalFinalBonus',1,'trustPressure',1];
  const deception = choice(deceptionDef[0], deceptionDef[1], { id:'deception', kind:'help_self', category:'Deception', personalStat:deceptionDef[2], personalGain:deceptionDef[3] || 1, trustCost:2, groupStat:deceptionDef[4], groupLoss:deceptionDef[5] || 1, betrayal:true });
  const choices = { primary_group:primary, secondary_group:secondary, personal, risk, deception };
  const pledgeOptions = ['primary_group','secondary_group','risk','personal'].map(id => ({ id, label: choices[id].label }));
  const publicEventLong = `${round.publicEvent}\n\n${guide.pressure || `The group cannot solve every danger surrounding ${round.title.toLowerCase()} at once.`}\n\nThe group must decide how many people will ${primary.label.toLowerCase()}, whether anyone will ${secondary.label.toLowerCase()}, and who is willing to attempt ${risk.label.toLowerCase()}. Any task left uncovered may shape the next round.`;
  const dangerText = round.failure?.text || `${ep.finalThreat} gains ground when the group leaves priorities unprotected.`;
  const resourceKeys = [...new Set([primary.groupStat, secondary.groupStat, risk.rewardStat, risk.groupStat, 'trustPressure'].filter(Boolean))];
  return {
    ...round,
    publicEventLong,
    immediateDangers:[dangerText, risk.preview, `${ep.finalThreat} can exploit division or an unprotected task.`],
    resourceKeys,
    discussionLead:`The group has limited time. Use the public discussion to build a plan, ask for commitments, challenge weak promises, and decide which danger can be left exposed.`,
    discussionPrompts:[
      `Who will publicly commit to ${primary.label.toLowerCase()}?`,
      `Is ${secondary.label.toLowerCase()} more urgent than ${primary.label.toLowerCase()}?`,
      `Who will support or protect anyone attempting ${risk.label.toLowerCase()}?`
    ],
    pledgeOptions,
    allianceLead:guide.alliance || `Private deals can change the public plan. Decide whom to recruit, what secret to trade, and whether your final action will match your public promise.`,
    allianceOptions:[
      `Recruit someone for “${primary.label}.”`,
      `Coordinate “${secondary.label}” with one trusted player.`,
      `Ask for protection while attempting “${risk.label}.”`,
      `Offer a resource or secret in exchange for loyalty.`,
      `Plan to break a public pledge without being exposed.`,
      `Warn an ally about a suspected betrayal.`
    ],
    resultBeat:guide.result || `The consequences of ${round.title.toLowerCase()} carry directly into the next crisis.`,
    choices
  };
}


const defaultOutcomes = {
  full: 'Full Rescue', broken: 'Broken Rescue', partial: 'One or Two Survive', wounded: 'The Threat Wins, But One Escapes Wounded', lost: 'Everyone Is Lost'
};

function mkEpisode(def) {
  const episode = {
    ...def,
    maxRounds: def.maxRounds || 6,
    modes: { standard: 'Standard · 55 minutes', quick: 'Quick · 35 minutes', long: 'Long · 75 minutes', ...(def.modes || {}) },
    statLabels: { ...baseStatLabels, ...(def.statLabels || {}) },
    groupStatLabels: { ...baseGroupLabels, ...(def.groupStatLabels || {}) },
    outcomes: { ...defaultOutcomes, ...(def.outcomes || {}) },
    storyCards: def.storyCards || storyCardsForEpisode(def.id)
  };
  episode.rounds = (def.rounds || []).map(round => enrichRound(episode, round));
  episode.privateCards = makePrivateCards(episode);
  return episode;
}

function privateOption(id, label, description, effects = {}, meta = {}) {
  return { id, label, description, effects, ...meta };
}

function makePrivateCards(ep) {
  const resource = ep.cardWords?.resource || 'hidden supplies';
  const tool = ep.cardWords?.tool || 'useful tool';
  const signal = ep.cardWords?.signal || 'signal piece';
  const clue = ep.cardWords?.clue || 'strange mark';
  const place = ep.cardWords?.place || 'dark corner';
  const threat = ep.finalThreat || 'the threat';
  const group = ep.groupName || 'group';
  const resourceStat = ep.cardWords?.resourceStat || 'foodSupply';
  const cards = {};

  for (let r = 1; r <= 6; r++) {
    const round = ep.rounds[r - 1];
    const primary = round.choices?.primary_group || Object.values(round.choices || {})[0] || { label: 'the main group task', groupStat: 'campSafety' };
    const secondary = round.choices?.secondary_group || primary;
    const risk = round.choices?.risk || primary;
    const primaryStat = primary.groupStat || 'campSafety';
    const secondaryStat = secondary.groupStat || primaryStat;

    cards[r] = [
      {
        id: `${ep.id}-r${r}c1`,
        title: `Hidden ${cap(resource)}`,
        type: 'Resource Dilemma',
        text: `During ${round.title}, you quietly find ${resource}. The ${group.toLowerCase()} does not know it exists, and the current plan is already short on resources.`,
        targetMode: 'other_player',
        options: [
          privateOption('share_all', `Add the ${resource} to the shared supply`, `Everyone can use it during this round. You give up control of who receives it.`, { [resourceStat]: 1, trust: 1 }, { visibility: 'public', publicResult: `{player} added hidden resources to the ${group.toLowerCase()}'s shared supply.`, classification: 'cooperative' }),
          privateOption('use_and_share', `Use part of it, then share the rest`, `You meet an immediate personal need while still contributing something to the group.`, { hunger: 1, [resourceStat]: 1 }, { visibility: 'public', publicResult: `{player} used part of a hidden resource and contributed the rest.`, classification: 'balanced' }),
          privateOption('reserve_emergency', `Keep it sealed for a genuine emergency`, `You keep a private reserve that may protect you or someone else later.`, { personalFinalBonus: 1 }, { visibility: 'private', classification: 'protective' }),
          privateOption('offer_target', `Offer it to {target} in exchange for help with “${primary.label}”`, `You try to turn the resource into a specific private agreement.`, { personalEscapeAdvantage: 1 }, { targetEffects: { trust: 1 }, visibility: 'private', classification: 'strategic' }),
          privateOption('keep_all', `Keep all of it hidden for yourself`, `You gain the strongest immediate benefit, but the group loses access to a resource it may need.`, { hunger: 2, trust: -1, hiddenThreat: 1 }, { visibility: 'anonymous', publicResult: `The group later realizes that some resources never reached the shared supply.`, classification: 'deceptive', betrayalWeight: 1 })
        ]
      },
      {
        id: `${ep.id}-r${r}c2`,
        title: 'Private Weakness',
        type: 'Personal Dilemma',
        text: `The pressure of ${round.title} is affecting you more than the others realize. You can still act, but hiding the problem may make the next decision harder.`,
        targetMode: 'other_player',
        options: [
          privateOption('tell_group', `Tell the group exactly what is happening`, `The plan can account for your condition, but everyone now knows you are vulnerable.`, { willToLive: 1, trust: 1 }, { visibility: 'public', publicResult: `{player} admitted a weakness before it became a larger problem.`, classification: 'honest' }),
          privateOption('ask_target', `Ask {target} privately to cover part of your task`, `You keep the problem limited to one person and create a personal obligation.`, { energy: 1 }, { targetEffects: { trust: 1 }, visibility: 'private', classification: 'strategic' }),
          privateOption('safer_duty', `Switch yourself to a safer duty`, `You stay useful without explaining every detail, but someone else may have to absorb the danger.`, { energy: 1, [secondaryStat]: 1 }, { visibility: 'public', publicResult: `{player} moved to a safer duty and still supported the secondary plan.`, classification: 'practical' }),
          privateOption('push_through', `Keep your assignment and push through`, `You preserve the public plan, but the effort may leave you weaker afterward.`, { energy: -1, willToLive: 1, trust: 1 }, { visibility: 'public', publicResult: `{player} kept working despite a private weakness.`, classification: 'sacrificial' }),
          privateOption('exaggerate', `Exaggerate the problem so someone else takes your place`, `You protect your energy by making the situation sound worse than it is.`, { energy: 2, trust: -1, hiddenThreat: 1 }, { visibility: 'anonymous', publicResult: `One assignment changed after the group acted on incomplete information.`, classification: 'manipulative', betrayalWeight: 1 })
        ]
      },
      {
        id: `${ep.id}-r${r}c3`,
        title: `The ${cap(tool)}`,
        type: 'Tool Dilemma',
        text: `You find a ${tool}. It could improve the plan for ${round.title}, support one player, or become leverage if the group begins to divide.`,
        targetMode: 'other_player',
        options: [
          privateOption('use_primary', `Use the ${tool} on “${primary.label}”`, `The main group priority gets an immediate boost.`, { [primaryStat]: 1, trust: 1 }, { visibility: 'public', publicResult: `{player} used a hidden ${tool} to strengthen the main plan.`, classification: 'cooperative' }),
          privateOption('loan_target', `Loan the ${tool} to {target} for “${secondary.label}”`, `You support a specific player and the secondary group priority.`, { [secondaryStat]: 1, trust: 1 }, { targetEffects: { trust: 1 }, visibility: 'public', publicResult: `{player} trusted {target} with a hidden ${tool}.`, classification: 'cooperative' }),
          privateOption('keep_backup', `Keep it as a backup if the public plan fails`, `You preserve a useful option for the final crisis without harming the current task directly.`, { personalFinalBonus: 1 }, { visibility: 'private', classification: 'protective' }),
          privateOption('trade_protection', `Offer it to {target} for protection during “${risk.label}”`, `You convert the tool into a private safety agreement.`, { personalEscapeAdvantage: 1 }, { targetEffects: { trust: 1 }, visibility: 'private', classification: 'strategic' }),
          privateOption('hide_leverage', `Hide it and control who can use it later`, `You keep the strongest leverage, but the group cannot use the tool now.`, { personalFinalBonus: 2, trust: -1, hiddenThreat: 1 }, { visibility: 'anonymous', publicResult: `A useful tool was withheld from the current plan.`, classification: 'deceptive', betrayalWeight: 1 })
        ]
      },
      {
        id: `${ep.id}-r${r}c4`,
        title: 'Suspicious Move',
        type: 'Suspicion Dilemma',
        text: `You notice {target} acting strangely near ${place}. You cannot tell whether they are scared, protecting something, or endangering the ${group.toLowerCase()}.`,
        targetMode: 'other_player',
        options: [
          privateOption('state_facts', `Tell the group exactly what you saw`, `You share the observation without claiming to know {target}'s motive.`, { threatAwareness: 1, trust: 1 }, { visibility: 'public', publicResult: `{player} reported seeing {target} near ${place} without making a direct accusation.`, classification: 'honest' }),
          privateOption('ask_target', `Ask {target} privately for an explanation`, `You give them a chance to explain before suspicion spreads.`, { trust: 1 }, { targetEffects: { trust: 1 }, visibility: 'private', classification: 'fair' }),
          privateOption('watch_target', `Say nothing and watch {target} during the next task`, `You gather leverage and information, but the group receives no warning yet.`, { personalFinalBonus: 1, threatAwareness: 1 }, { visibility: 'private', classification: 'cautious' }),
          privateOption('tell_alliance', `Share the suspicion only with your alliance`, `Your allies can prepare together, but the wider group remains uninformed.`, { personalEscapeAdvantage: 1 }, { visibility: 'private', classification: 'strategic' }),
          privateOption('accuse_target', `Publicly accuse {target} of endangering the group`, `A direct accusation may force answers, but it can damage both players if the evidence is weak.`, { threatAwareness: 1, trust: -1, trustPressure: 1 }, { targetEffects: { trust: -1 }, visibility: 'public', publicResult: `{player} publicly accused {target} of endangering the group.`, classification: 'confrontational', betrayalWeight: 1 })
        ]
      },
      {
        id: `${ep.id}-r${r}c5`,
        title: `Damaged ${cap(signal)}`,
        type: 'Escape Dilemma',
        text: `You discover a damaged ${signal}. It may improve the group's escape plan, expose the group to ${threat}, or give one person a private advantage.`,
        targetMode: 'other_player',
        options: [
          privateOption('give_group', `Turn it over to the group`, `Everyone knows it exists and it becomes part of the official escape plan.`, { escapeProgress: 1, trust: 1 }, { visibility: 'public', publicResult: `{player} contributed a damaged ${signal} to the group escape plan.`, classification: 'cooperative' }),
          privateOption('repair_target', `Ask {target} to repair it with you`, `Two players share control of the information and move the escape plan forward.`, { escapeProgress: 1, energy: -1 }, { targetEffects: { trust: 1 }, visibility: 'public', publicResult: `{player} and {target} worked together on the damaged ${signal}.`, classification: 'cooperative' }),
          privateOption('test_now', `Test it immediately`, `You may gain faster escape progress, but the signal could attract ${threat}.`, { escapeProgress: 2, hiddenThreat: 1 }, { visibility: 'public', publicResult: `{player} tested the ${signal} before the group was fully prepared.`, classification: 'risky' }),
          privateOption('save_until_ready', `Keep it safe until the group is ready`, `You preserve it for a later phase without claiming it as your private escape route.`, { personalFinalBonus: 1 }, { visibility: 'private', classification: 'protective' }),
          privateOption('private_route', `Keep it for a private escape route`, `You increase your own escape options while the public plan remains incomplete.`, { personalEscapeAdvantage: 2, escapeProgress: -1, trust: -1 }, { visibility: 'anonymous', publicResult: `A piece of the escape plan was kept outside the group's control.`, classification: 'deceptive', betrayalWeight: 1 })
        ]
      },
      {
        id: `${ep.id}-r${r}c6`,
        title: 'The Pattern',
        type: 'Clue Dilemma',
        text: `You find ${clue}. It suggests ${threat} is responding to division inside the group, but you do not yet know whether the pattern is complete.`,
        targetMode: 'other_player',
        options: [
          privateOption('reveal_pattern', `Show the full clue to everyone`, `The group gains knowledge immediately, even if the clue creates fear.`, { cluesFound: 1, threatAwareness: 1, trust: 1 }, { visibility: 'public', publicResult: `{player} revealed a clue connecting ${threat} to the group's division.`, classification: 'honest' }),
          privateOption('tell_target', `Show the clue only to {target}`, `You create a two-person information advantage and ask them to help verify it.`, { personalFinalBonus: 1 }, { targetEffects: { trust: 1 }, visibility: 'private', classification: 'strategic' }),
          privateOption('test_pattern', `Test the pattern before warning everyone`, `You may learn more, but testing it could draw ${threat} closer.`, { threatAwareness: 2, energy: -1, hiddenThreat: 1 }, { visibility: 'public', publicResult: `{player} tested a dangerous pattern and learned more about ${threat}.`, classification: 'risky' }),
          privateOption('hold_for_proof', `Keep the clue until you have proof`, `You avoid causing panic but carry the fear alone.`, { personalFinalBonus: 1, willToLive: -1 }, { visibility: 'private', classification: 'cautious' }),
          privateOption('alter_clue', `Alter the clue so it supports your own plan`, `You gain leverage by changing what others will eventually believe.`, { personalEscapeAdvantage: 1, trust: -2, hiddenThreat: 1 }, { visibility: 'anonymous', publicResult: `A clue reached the group in an altered or incomplete form.`, classification: 'deceptive', betrayalWeight: 2 })
        ]
      }
    ];
  }
  return cards;
}

function cap(s) { return String(s).replace(/^./, c => c.toUpperCase()); }

