      {number:6,title:'Final Negotiation',publicEvent:'Police offer a deal. The vault is open. The breach team is moving.',groupGoal:'Decide whether to escape together or sell someone out.',choices:{help_group:choice('Coordinate the Getaway','Getaway Progress rises.',{energyCost:2,groupStat:'escapeProgress',groupGain:2}),help_self:choice('Prepare to Cut a Deal','Getaway advantage rises, trust drops.',{personalEscapeGain:2,trustCost:2}),take_risk:choice('Expose the Informant','Getaway bonus may rise, injury risk high.',{energyCost:2,finalBonusGain:1,injuryChance:.50,clueChance:.70,clueText:'The police breach depends on the crew betraying each other first.'})},teamBonus:{threshold:3,stat:'escapeProgress',amount:2,text:'The crew can still escape as a unit.'},trapBonus:{threshold:2,amount:2,text:'The informant plan is exposed enough to use against the police.'}}
