    finalChoices:{fight_together:{label:'Escape Together',description:'Best if crew loyalty and getaway progress are high.'},set_trap:{label:'Expose the Informant',description:'Best with informant intel and evidence.'},run_raft:{label:'Run the Getaway',description:'Best if getaway progress is high.'},sacrifice:{label:'Take the Fall',description:'May save the crew but gets you caught.'},betray_group:{label:'Cut a Deal',description:'May save you but can doom the crew.'}},
