function getEpisode(id) { return episodes[id] || episodes.island; }
function episodeSummaries() { return Object.values(episodes).map(e => ({ id: e.id, title: e.title, subtitle: e.subtitle, tagline: e.tagline, finalThreat: e.finalThreat, venueDefault: e.venueDefault })); }

module.exports = { episodes, getEpisode, episodeSummaries };
